// ---- UAnimNotify::* ----
uint8_t UAnimNotify::Received_Notify(struct USkeletalMeshComponent* MeshComp, struct UAnimSequenceBase* Animation)
{
    static struct UFunction* Func = nullptr;
    if (!Func) Func = ClassPrivate->GetFunction("AnimNotify", "Received_Notify");
    struct
    {
        struct USkeletalMeshComponent* MeshComp;
        struct UAnimSequenceBase* Animation;
        uint8_t ReturnValue;
    } Parms{};
    Parms.MeshComp = (struct USkeletalMeshComponent*)MeshComp;
    Parms.Animation = (struct UAnimSequenceBase*)Animation;
    this->ProcessEvent(Func, &Parms);
    return Parms.ReturnValue;
}

